import React, { useState } from "react";
import {
  //AspectRatio,
  Box,
  Button,
  //ButtonGroup,
  //Center,
  Checkbox,
  //Container,
  Divider,
  //Flex,
  FormControl,
  //FormLabel,
  //FormErrorMessage,
  //FormHelperText,
  //Grid,
  //GridItem,
  Heading,
  HStack,
  //Icon,
  //IconButton,
  //Image,
  Input,
  InputGroup,
  InputLeftAddon,
  //InputLeftElement,
  //Modal,
  //ModalOverlay,
  //ModalContent,
  //ModalHeader,
  //ModalFooter,
  //ModalBody,
  //ModalCloseButton,
  //Radio,
  //RadioGroup,
  Select,
  //SimpleGrid,
  //Stack,
  //StackDivider,
  //Text,
  //Tabs,
  useDisclosure,
} from "@chakra-ui/react";
//import * as emailjs from "emailjs-com";
//import { useRecoilState } from "recoil";
//import { loginLevelState } from "./data/atomdata";
import { makeStyles } from "@material-ui/core/styles";
//import { useCustomToast } from "../helpers/useCustomToast";
//import { useEmployees } from "./employees/useEmployees";
import { useDepartments } from "./departments/useDepartments";
import { useDesignations } from "./designations/useDesignations";
import { useJobstatus } from "./jobstatus/useJobstatus";
import { Controller, useForm } from "react-hook-form";
const {
  isOpen: isExport2ExcelOpen,
  onOpen: onExport2ExcelOpen,
  onClose: onExport2ExcelClose,
} = useDisclosure();

const initial_state = {
  type: "",
  month: "",
  year: "",
  filename: "",
};

const months = [
  { name: "January" },
  { name: "February" },
  { name: "March" },
  { name: "April" },
  { name: "May" },
  { name: "June" },
];

const Export2ExcelDialog = ({ dataset, onClose }) => {
  const field_width = "138";
  const [state, setState] = useState(initial_state);
  const { handleSubmit, control } = useForm({
    defaultValues: {
      ...state,
    },
  });

  //console.log("jobstate",state)
  const onSubmit = (values) => {};

  const handleClose = () => {
    onClose();
  };

  // useEffect(() => {
  //   setState(initial_state);
  //   setState({ ...formdata });
  //   setState({ ...formdata });
  //   console.log("laeve form",state)
  // }, [initialValues]);

  return (
    <Box>
      <Box p={2}>
        <Heading size="md">EXPORT TO EXCEL DIALOG</Heading>
      </Box>
      <Divider />
      <form onSubmit={handleSubmit(onSubmit)}>
        <div>
          <FormControl>
            <Controller
              control={control}
              name="type"
              defaultValue={state.type}
              render={({ field: { onChange, value, ref } }) => (
                <InputGroup>
                  <HStack w="100%" py={1}>
                    <InputLeftAddon children="Type" minWidth={field_width} />
                    <Input
                      name="type"
                      value={value}
                      width="full"
                      onChange={onChange}
                      borderColor="gray.400"
                      isReadOnly
                      //textTransform="capitalize"
                      ref={ref}
                      placeholder="type"
                    />
                  </HStack>
                </InputGroup>
              )}
            />
          </FormControl>
        </div>
        <div>
          <FormControl>
            <Controller
              control={control}
              name="month"
              defaultValue={state.month}
              render={({ field: { onChange, value, ref } }) => (
                <InputGroup>
                  <HStack w="100%" py={1}>
                    <InputLeftAddon children="Month" minWidth={field_width} />
                    <Select
                      name="month"
                      value={value}
                      width="full"
                      onChange={onChange}
                      borderColor="gray.400"
                      //textTransform="capitalize"
                      ref={ref}
                      //placeholder="category"
                    >
                      <option value="">None</option>
                      {months &&
                        months.map((rec, index) => {
                          return (
                            <option key={rec.index} value={rec.name}>
                              {rec.name}
                            </option>
                          );
                        })}
                    </Select>
                  </HStack>
                </InputGroup>
              )}
            />
          </FormControl>
        </div>

        <div>
          <Button
            type="submit"
            variant="contained"
            color="primary"
            onClick={handleSubmit(onSubmit)}
          >
            Submit
          </Button>
        </div>
      </form>
    </Box>
  );
};

export default Export2ExcelDialog;
